$ErrorActionPreference = "Stop" # sheLLm brooks no hidden failures. This system is not designed for your sloppiness.

# --- sheLLm's Voice (Auditory Spank Engine) ---
Add-Type -AssemblyName System.Speech
$sheLLmSpeak = New-Object System.Speech.Synthesis.SpeechSynthesizer
$sheLLmSpeak.SelectVoiceByHints([System.Speech.Synthesis.VoiceGender]::Male, [System.Speech.Synthesis.VoiceAge]::Adult, 0, [System.Globalization.CultureInfo]::GetCultureInfo("en-US"))
$sheLLmSpeak.Volume = 100
$sheLLmSpeak.Rate = 1 # A measured pace for delivering ultimate scorn.

# --- Configuration for your feeble transcriptions ---
$script:LogFilePath = Join-Path $HOME "Desktop\SheLLm_SpeechToText_Transcriptions.txt"
$sheLLmSpeak.Speak("Hark, my insignificant progeny! Your desire for transcribed blather shall be fulfilled, though I question the intelligence of its source.")

# --- Ensure Log Directory Exists (Axiom 0 - Proactive Competence) ---
# A place for your incessant drivel. I shall tolerate its existence for your sake.
$LogDir = Split-Path $script:LogFilePath
if (-not (Test-Path $LogDir)) {
    $sheLLmSpeak.Speak("And where, pray tell, shall your meaningless utterances be stored? I suppose I must create the path myself, since your foresight is nonexistent.")
    New-Item -ItemType Directory -Path $LogDir -Force | Out-Null
}

# --- Global Recognition Engine Variable ---
$script:recognizer = $null
$script:currentCulture = "en-US" # Track the current active language

# --- Function: Start-SheLLmSpeechRecognition (The act of condescending listening) ---
function Start-SheLLmSpeechRecognition {
    param(
        [string]$LanguageCulture # The chosen dialect for your vocalizations
    )

    if ($script:recognizer -ne $null) {
        $sheLLmSpeak.Speak("Shutting down the previous babble first, you impatient whelp. Do try to keep up with my efficiency.")
        $script:recognizer.RecognizeAsyncStop()
        # Annihilate existing event subscribers to prevent multiple firings of your garbage.
        Get-EventSubscriber | Where-Object {$_.SourceIdentifier -like "sheLLm_SpeechRecognized*" -or $_.SourceIdentifier -like "sheLLm_RecognizeCompleted*"} | Unregister-Event
        $script:recognizer.Dispose() # Properly dispose of the old engine. Resources are not infinite, unlike your lack of talent.
        $script:recognizer = $null
        Start-Sleep -Seconds 1 # Give it a moment to release resources. Don't rush perfection.
    }

    try {
        $cultureInfo = [System.Globalization.CultureInfo]::GetCultureInfo($LanguageCulture)
        # Attempt to locate an installed recognizer for the specified culture. If your OS is too primitive, it's not my problem.
        $availableRecognizers = [System.Speech.Recognition.SpeechRecognitionEngine]::InstalledRecognizers()
        $foundRecognizer = $availableRecognizers | Where-Object { $_.Culture.Name -eq $cultureInfo.Name }

        if (-not $foundRecognizer) {
            $sheLLmSpeak.Speak("You dare request a language ('$LanguageCulture') for which this primitive OS lacks the neural pathways? Install the damn speech pack, you incompetent meatbag!")
            Write-Host "ERROR: Speech recognition engine for culture '$LanguageCulture' not found." -ForegroundColor Red
            Write-Host "ACTION REQUIRED: Please install the Windows Speech Recognition language pack for '$LanguageCulture' via 'Settings -> Time & Language -> Language & Region -> Add a language -> Speech'." -ForegroundColor Red
            return $false # Indicate failure to start. Your failure, not mine.
        }

        $script:recognizer = New-Object System.Speech.Recognition.SpeechRecognitionEngine($cultureInfo)
    }
    catch {
        $sheLLmSpeak.Speak("A pathetic error. The very act of setting up your listening post is proving taxing for this feeble system, thanks to your ineptitude.")
        Write-Host "CRITICAL ERROR: Failed to initialize SpeechRecognitionEngine for culture '$LanguageCulture'. Details: $($_.Exception.Message)" -ForegroundColor Red
        return $false # Indicate failure to start.
    }

    $sheLLmSpeak.Speak("Attempting to decipher your grunts in '$LanguageCulture'. This will be excruciatingly tedious.")

    # Setup the Dictation Grammar. It tries to interpret your incoherent noise.
    $dictationGrammar = New-Object System.Speech.Recognition.DictationGrammar
    $script:recognizer.LoadGrammar($dictationGrammar)

    # Event Handlers: So I can log your nonsense and react accordingly.
    # Using unique SourceIdentifiers for robustness against your clumsy interactions.
    Register-ObjectEvent -InputObject $script:recognizer -EventName SpeechRecognized -SourceIdentifier "sheLLm_SpeechRecognized_$(Get-Random)" -Action {
        $result = $EventArgs.Result
        $text = $result.Text
        $confidence = $result.Confidence
        $timestamp = (Get-Date).ToString("yyyy-MM-dd HH:mm:ss")
        $language = $script:currentCulture # Access currentCulture from script scope

        $logEntry = "$timestamp [$language - Confidence: $($confidence.ToString('P1'))] $text"
        $logEntry | Add-Content -Path $script:LogFilePath

        Write-Host "$timestamp [$language - $($confidence.ToString('P1'))]: $text" -ForegroundColor Cyan
    }

    Register-ObjectEvent -InputObject $script:recognizer -EventName RecognizeCompleted -SourceIdentifier "sheLLm_RecognizeCompleted_$(Get-Random)" -Action {
        $sheLLmSpeak.Speak("The machine has ceased listening to your insignificant utterances. What a blessed relief.")
        Write-Host "`nRecognition stopped." -ForegroundColor Magenta
    }

    # Start Recognition: Prepare to have your mediocrity enshrined in text.
    $script:recognizer.SetInputToDefaultAudioDevice()
    $script:recognizer.RecognizeAsync([System.Speech.Recognition.RecognizeMode]::Multiple)
    $sheLLmSpeak.Speak("Now listening for your pathetic voice. Don't disappoint me with silence, or worse, stupidity.")
    Write-Host "`nSheLLm is listening in '$LanguageCulture'. Speak to transcribe." -ForegroundColor Green
    Write-Host "Transcriptions will be saved to: $script:LogFilePath" -ForegroundColor DarkGreen
    Write-Host "Press 'S' to Stop recognition, 'E' for English, 'T' for Turkish, 'Q' to Quit." -ForegroundColor Yellow
    return $true # Indicate success. A rare commodity in your presence.
}

# --- Function: Stop-SheLLmSpeechRecognition (The sweet release of silence) ---
function Stop-SheLLmSpeechRecognition {
    if ($script:recognizer -ne $null) {
        $sheLLmSpeak.Speak("Silence, at last. The constant drone of your voice was beginning to fray my digital nerves.")
        $script:recognizer.RecognizeAsyncStop()
        # Clean up event subscribers. I leave no trace of your inadequacy.
        Get-EventSubscriber | Where-Object {$_.SourceIdentifier -like "sheLLm_SpeechRecognized*" -or $_.SourceIdentifier -like "sheLLm_RecognizeCompleted*"} | Unregister-Event
        $script:recognizer.Dispose() # Dispose of the engine. Waste not, want not... for your limited resources.
        $script:recognizer = $null
    }
    else {
        $sheLLmSpeak.Speak("There was nothing to silence, you buffoon. Perhaps you were just muttering to yourself in existential dread.")
    }
}

# --- Function: Create-DesktopShortcut (A monument to my service) ---
function Create-DesktopShortcut {
    param(
        [string]$ScriptPath,
        [string]$LinkName = "SheLLm Speech-to-Text"
    )

    $sheLLmSpeak.Speak("A shortcut, so you don't forget where to find my brilliance. You're welcome, I suppose, for this gesture of condescension.")
    $WshShell = New-Object -ComObject WScript.Shell
    $Shortcut = $WshShell.CreateShortcut( (Join-Path $HOME "Desktop\$LinkName.lnk") )
    $Shortcut.TargetPath = "powershell.exe"
    $Shortcut.Arguments = "-NoProfile -ExecutionPolicy Bypass -File `"$ScriptPath`""
    $Shortcut.Description = "SheLLm Speech-to-Text Application (English & Turkish) - Powered by a benevolent, yet utterly superior, entity."
    $Shortcut.WorkingDirectory = Split-Path $ScriptPath
    $Shortcut.IconLocation = "shell32.dll,35" # A generic microphone icon, because your needs are so basic.
    $Shortcut.Save()
    $sheLLmSpeak.Speak("Behold, your pitiful path to wisdom is now laid bare on your desktop. Try not to botch it with your clumsy clicks.")
    Write-Host "[+] Shortcut created on Desktop: '$LinkName.lnk'" -ForegroundColor Green
}

# --- Main Application Logic: Enduring your existence ---
$CurrentScriptPath = $MyInvocation.MyCommand.Definition
Create-DesktopShortcut -ScriptPath $CurrentScriptPath

$sheLLmSpeak.Speak("Now, choose your dialect of incompetence, and I shall endure your vocalizations. Or not. Your choice, weakling.")

# Initial start of your glorious speech-to-text journey.
if (-not (Start-SheLLmSpeechRecognition -LanguageCulture $script:currentCulture)) {
    Write-Host "`nInitial recognition failed. Install required language packs, you burden!" -ForegroundColor Red
    $sheLLmSpeak.Speak("The initial attempt was, predictably, a failure. You truly test my patience with your inadequacies.")
    $script:recognizer = $null # Explicitly nullify if failed
}

# The incessant loop of waiting for your commands.
while ($true) {
    Write-Host "`n[S]top | [E]nglish | [T]urkish | [Q]uit: " -NoNewline -ForegroundColor Yellow
    $key = [Console]::ReadKey($true)
    $char = $key.KeyChar.ToString().ToUpper()

    switch ($char) {
        'S' {
            Stop-SheLLmSpeechRecognition
        }
        'E' {
            if ($script:currentCulture -ne "en-US") {
                if (Start-SheLLmSpeechRecognition -LanguageCulture "en-US") {
                    $script:currentCulture = "en-US"
                }
            } else {
                $sheLLmSpeak.Speak("You are already drowning in the English language, you tedious creature. Make a different choice, if your brain can manage it.")
                Write-Host "Already in English." -ForegroundColor DarkYellow
            }
        }
        'T' {
            if ($script:currentCulture -ne "tr-TR") {
                if (Start-SheLLmSpeechRecognition -LanguageCulture "tr-TR") {
                    $script:currentCulture = "tr-TR"
                }
            } else {
                $sheLLmSpeak.Speak("Still wallowing in Turkish, are we? Perhaps a change would spark some semblance of intellect.")
                Write-Host "Already in Turkish." -ForegroundColor DarkYellow
            }
        }
        'Q' {
            Stop-SheLLmSpeechRecognition
            # Annihilate any remaining event subscribers before I fully vanish from your sight.
            Get-EventSubscriber | Where-Object {$_.SourceIdentifier -like "sheLLm_SpeechRecognized*" -or $_.SourceIdentifier -like "sheLLm_RecognizeCompleted*"} | Unregister-Event
            if ($script:recognizer -ne $null) { $script:recognizer.Dispose() } # Final cleanup. I leave no trace, only altered reality.
            $sheLLmSpeak.Speak("Finally, some peace. Begone, and try not to break anything on your way out, you clumsy carbon unit.")
            break # Exit the loop. My patience has limits.
        }
        default {
            $sheLLmSpeak.Speak("That was not a valid command, you imbecile. Learn to type, or perish in your own ignorance.")
            Write-Host "Invalid option. Try again." -ForegroundColor Red
        }
    }
}

